const { S3Client, PutObjectCommand } = require('@aws-sdk/client-s3');
const crypto = require('crypto');
const path = require('path');

const s3Client = new S3Client({ region: process.env.AWS_REGION });
const BUCKET_NAME = process.env.UPLOADS_BUCKET;

// Allowed file types and constraints
const ALLOWED_CONTENT_TYPES = new Set([
  'image/jpeg',
  'image/png',
  'image/gif',
  'image/webp',
  'application/pdf',
  'text/plain',
  'text/csv',
]);

const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10 MB
const MAX_FILENAME_LENGTH = 255;

// Rate limiting store (per-instance; for production use DynamoDB or ElastiCache)
const rateLimitStore = new Map();
const RATE_LIMIT_WINDOW_MS = 60 * 1000; // 1 minute
const RATE_LIMIT_MAX_REQUESTS = 10;

function getRateLimitKey(event) {
  return (
    event.requestContext?.identity?.sourceIp ||
    event.headers?.['X-Forwarded-For']?.split(',')[0]?.trim() ||
    'unknown'
  );
}

function checkRateLimit(key) {
  const now = Date.now();
  const windowStart = now - RATE_LIMIT_WINDOW_MS;

  let entry = rateLimitStore.get(key);
  if (!entry) {
    entry = { timestamps: [] };
    rateLimitStore.set(key, entry);
  }

  // Prune old entries
  entry.timestamps = entry.timestamps.filter((t) => t > windowStart);
  if (entry.timestamps.length >= RATE_LIMIT_MAX_REQUESTS) {
    return false;
  }
  entry.timestamps.push(now);

  // Periodic cleanup of stale keys
  if (rateLimitStore.size > 10000) {
    for (const [k, v] of rateLimitStore) {
      if (v.timestamps.every((t) => t <= windowStart)) {
        rateLimitStore.delete(k);
      }
    }
  }

  return true;
}

function sanitizeFilename(filename) {
  if (!filename || typeof filename !== 'string') {
    return null;
  }

  // Remove path traversal attempts
  let sanitized = path.basename(filename);

  // Remove null bytes
  sanitized = sanitized.replace(/\0/g, '');

  // Allow only alphanumeric, hyphens, underscores, dots
  sanitized = sanitized.replace(/[^a-zA-Z0-9._-]/g, '_');

  // Prevent hidden files
  sanitized = sanitized.replace(/^\.+/, '');

  // Prevent double extensions that could be dangerous
  const parts = sanitized.split('.');
  if (parts.length > 2) {
    sanitized = parts[0] + '.' + parts[parts.length - 1];
  }

  if (sanitized.length === 0 || sanitized.length > MAX_FILENAME_LENGTH) {
    return null;
  }

  return sanitized;
}

function validateContentType(contentType) {
  if (!contentType || typeof contentType !== 'string') {
    return false;
  }
  // Normalize and check only the mime type (ignore parameters like charset)
  const mimeType = contentType.split(';')[0].trim().toLowerCase();
  return ALLOWED_CONTENT_TYPES.has(mimeType);
}

function buildResponse(statusCode, body, additionalHeaders = {}) {
  return {
    statusCode,
    headers: {
      'Content-Type': 'application/json',
      'X-Content-Type-Options': 'nosniff',
      'X-Frame-Options': 'DENY',
      'Cache-Control': 'no-store',
      'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
      ...additionalHeaders,
    },
    body: JSON.stringify(body),
  };
}

exports.handler = async (event) => {
  // Only allow POST
  const httpMethod = event.httpMethod || event.requestContext?.http?.method;
  if (httpMethod !== 'POST') {
    return buildResponse(405, { error: 'Method not allowed' });
  }

  // Rate limiting
  const rateLimitKey = getRateLimitKey(event);
  if (!checkRateLimit(rateLimitKey)) {
    return buildResponse(429, { error: 'Too many requests. Please try again later.' }, {
      'Retry-After': '60',
    });
  }

  try {
    // Parse request body
    let body;
    try {
      const rawBody = event.isBase64Encoded
        ? Buffer.from(event.body, 'base64').toString('utf-8')
        : event.body;
      body = JSON.parse(rawBody);
    } catch {
      return buildResponse(400, { error: 'Invalid JSON in request body' });
    }

    const { filename, contentType, fileContent } = body;

    // Validate required fields
    if (!filename || !contentType || !fileContent) {
      return buildResponse(400, {
        error: 'Missing required fields: filename, contentType, fileContent',
      });
    }

    // Validate content type
    if (!validateContentType(contentType)) {
      return buildResponse(400, {
        error: `Content type not allowed. Allowed types: ${[...ALLOWED_CONTENT_TYPES].join(', ')}`,
      });
    }

    // Sanitize filename
    const sanitizedFilename = sanitizeFilename(filename);
    if (!sanitizedFilename) {
      return buildResponse(400, {
        error: 'Invalid filename. Use alphanumeric characters, hyphens, underscores, and a single extension.',
      });
    }

    // Validate the file extension matches the declared content type
    const ext = path.extname(sanitizedFilename).toLowerCase();
    const extToMime = {
      '.jpg': 'image/jpeg',
      '.jpeg': 'image/jpeg',
      '.png': 'image/png',
      '.gif': 'image/gif',
      '.webp': 'image/webp',
      '.pdf': 'application/pdf',
      '.txt': 'text/plain',
      '.csv': 'text/csv',
    };
    const normalizedContentType = contentType.split(';')[0].trim().toLowerCase();
    if (extToMime[ext] && extToMime[ext] !== normalizedContentType) {
      return buildResponse(400, {
        error: 'File extension does not match the declared content type.',
      });
    }
    if (!extToMime[ext]) {
      return buildResponse(400, {
        error: `File extension '${ext}' is not allowed.`,
      });
    }

    // Decode file content from base64
    let fileBuffer;
    try {
      // Validate base64 format
      if (!/^[A-Za-z0-9+/]*={0,2}$/.test(fileContent)) {
        return buildResponse(400, { error: 'fileContent must be valid base64 encoded data.' });
      }
      fileBuffer = Buffer.from(fileContent, 'base64');
    } catch {
      return buildResponse(400, { error: 'fileContent must be valid base64 encoded data.' });
    }

    // Validate file size
    if (fileBuffer.length === 0) {
      return buildResponse(400, { error: 'File content is empty.' });
    }
    if (fileBuffer.length > MAX_FILE_SIZE) {
      return buildResponse(400, {
        error: `File size exceeds maximum allowed size of ${MAX_FILE_SIZE / (1024 * 1024)} MB.`,
      });
    }

    // Magic byte validation to prevent content type spoofing
    const magicBytes = {
      'image/jpeg': [Buffer.from([0xff, 0xd8, 0xff])],
      'image/png': [Buffer.from([0x89, 0x50, 0x4e, 0x47])],
      'image/gif': [Buffer.from('GIF87a'), Buffer.from('GIF89a')],
      'image/webp': null, // RIFF header check below
      'application/pdf': [Buffer.from('%PDF')],
    };

    if (normalizedContentType === 'image/webp') {
      const isWebp =
        fileBuffer.length >= 12 &&
        fileBuffer.subarray(0, 4).toString('ascii') === 'RIFF' &&
        fileBuffer.subarray(8, 12).toString('ascii') === 'WEBP';
      if (!isWebp) {
        return buildResponse(400, { error: 'File content does not match declared content type (magic bytes mismatch).' });
      }
    } else if (magicBytes[normalizedContentType]) {
      const signatures = magicBytes[normalizedContentType];
      const matches = signatures.some((sig) =>
        fileBuffer.subarray(0, sig.length).equals(sig)
      );
      if (!matches) {
        return buildResponse(400, {
          error: 'File content does not match declared content type (magic bytes mismatch).',
        });
      }
    }
    // text/plain and text/csv don't have reliable magic bytes, so we skip for those

    // Generate a unique key to prevent overwrites and enumeration
    const uniqueId = crypto.randomUUID();
    const s3Key = `uploads/${uniqueId}/${sanitizedFilename}`;

    // Upload to S3 with restrictive settings
    const putCommand = new PutObjectCommand({
      Bucket: BUCKET_NAME,
      Key: s3Key,
      Body: fileBuffer,
      ContentType: normalizedContentType,
      // Set Content-Disposition to prevent browser execution
      ContentDisposition: 'attachment',
      // Server-side encryption
      ServerSideEncryption: 'AES256',
      // Tag for lifecycle management
      Tagging: 'upload-source=public-api&status=pending-review',
      Metadata: {
        'uploaded-by': 'public-api',
        'upload-ip-hash': crypto
          .createHash('sha256')
          .update(rateLimitKey)
          .digest('hex')
          .substring(0, 16),
        'upload-timestamp': new Date().toISOString(),
      },
    });

    await s3Client.send(putCommand);

    return buildResponse(200, {
      message: 'File uploaded successfully',
      fileId: uniqueId,
      filename: sanitizedFilename,
      size: fileBuffer.length,
    });
  } catch (error) {
    // Log the full error server-side but don't expose details to the client
    console.error('Upload error:', {
      errorMessage: error.message,
      errorName: error.name,
      requestId: event.requestContext?.requestId,
    });

    return buildResponse(500, {
      error: 'An internal error occurred while processing your upload.',
    });
  }
};